seed_files.utils.py:
"""Utility module for the data pipeline.

Provides a registry of reusable stage functions that can be looked up by name.
"""


def uppercase(data):
    """Convert all string values to uppercase."""
    if isinstance(data, dict):
        return {k: v.upper() if isinstance(v, str) else v for k, v in data.items()}
    if isinstance(data, list):
        return [item.upper() if isinstance(item, str) else item for item in data]
    if isinstance(data, str):
        return data.upper()
    return data


def double_numbers(data):
    """Double all numeric values."""
    if isinstance(data, dict):
        return {k: v * 2 if isinstance(v, (int, float)) else v for k, v in data.items()}
    if isinstance(data, list):
        return [item * 2 if isinstance(item, (int, float)) else item for item in data]
    if isinstance(data, (int, float)):
        return data * 2
    return data


def strip_whitespace(data):
    """Strip leading/trailing whitespace from string values."""
    if isinstance(data, dict):
        return {k: v.strip() if isinstance(v, str) else v for k, v in data.items()}
    if isinstance(data, list):
        return [item.strip() if isinstance(item, str) else item for item in data]
    if isinstance(data, str):
        return data.strip()
    return data


def add_timestamp(data):
    """Add a _processed key to dict data."""
    if isinstance(data, dict):
        result = dict(data)
        result["_processed"] = True
        return result
    return data


def fail_always(data):
    """A stage that always raises an error. Used for testing error handling."""
    raise ValueError("intentional failure from fail_always")


STAGE_REGISTRY = {
    "uppercase": uppercase,
    "double_numbers": double_numbers,
    "strip_whitespace": strip_whitespace,
    "add_timestamp": add_timestamp,
    "fail_always": fail_always,
}
